func endpointMetadata(cmd *cobra.Command) (method, path, endpoint string) {
	if cmd == nil || cmd.Annotations == nil {
		return "", "", ""
	}
	return strings.ToUpper(cmd.Annotations["pp:method"]), cmd.Annotations["pp:path"], cmd.Annotations["pp:endpoint"]
}

func isUngatedValidationRoute(method, path string) bool {
	if method != "POST" {
		return false
	}
	path = strings.ToLower(path)
	switch path {
	case "/v1/agents/resolution",
		"/v1/domains/available",
		"/v1/domains/contacts/validate",
		"/v1/domains/purchase/validate":
		return true
	}
	if strings.HasSuffix(path, "/transfer/validate") && strings.Contains(path, "/domains/") {
		return true
	}
	if strings.HasSuffix(path, "/domains/register/validate") {
		return true
	}
	return false
}

func isDNSRecordReplace(method, path string) bool {
	return method == "PUT" && strings.Contains(strings.ToLower(path), "/records")
}

func isDNSRecordDelete(method, path string) bool {
	return method == "DELETE" && strings.Contains(strings.ToLower(path), "/records")
}

func containsAny(s string, needles ...string) bool {
	for _, needle := range needles {
		if strings.Contains(s, needle) {
			return true
		}
	}
	return false
}

func appendRiskWarning(cmd *cobra.Command, warning string) {
	if warning == "" {
		return
	}
	block := "Risk warning: " + warning
	if strings.Contains(cmd.Long, block) {
		return
	}
	if strings.TrimSpace(cmd.Long) == "" {
		cmd.Long = block
		return
	}
	cmd.Long = strings.TrimRight(cmd.Long, "\n") + "\n\n" + block
}
